import React, { useState } from "react";
import ProductCard from "./components/ProductCard";

const products = [
  { id: 1, name: "Gold Necklace", price: 7500, image: "/images/necklace.jpg" },
  { id: 2, name: "Diamond Ring", price: 15000, image: "/images/ring.jpg" },
  { id: 3, name: "Silver Bracelet", price: 5000, image: "/images/bracelet.jpg" },
  { id: 4, name: "Pearl Earrings", price: 3500, image: "/images/earrings.jpg" },
  { id: 5, name: "Luxury Watch", price: 12000, image: "/images/watch.jpg" },
  { id: 6, name: "Emerald Pendant", price: 9000, image: "/images/pendant.jpg" }
];

function App() {
  const [cart, setCart] = useState([]);
  const [page, setPage] = useState("home");

  const addToCart = (product) => {
    setCart([...cart, product]);
  };

  const removeFromCart = (index) => {
    const newCart = [...cart];
    newCart.splice(index, 1);
    setCart(newCart);
  };

  const totalPrice = cart.reduce((sum, item) => sum + item.price, 0);

  return (
    <div className="bg-white min-h-screen">
      <header className="p-4 flex justify-between items-center">
        <h1 className="text-2xl font-bold">Luxe Jewellery</h1>
        <nav>
          <button onClick={() => setPage("products")} className="px-3 text-gray-700">Products</button>
          <button onClick={() => setPage("contact")} className="px-3 text-gray-700">Contact</button>
          <button onClick={() => setPage("cart")} className="px-3 text-gray-700">Cart ({cart.length})</button>
        </nav>
      </header>

      {page === "home" && (
        <section className="relative text-center">
          <video 
            src="/videos/home.mp4" 
            autoPlay 
            muted 
            loop 
            className="w-full h-96 object-cover"
          />
          <div className="absolute inset-0 flex flex-col justify-center items-center bg-black bg-opacity-30">
            <h2 className="text-4xl font-bold text-white">Timeless Elegance</h2>
            <p className="text-white mt-2">Discover affordable luxury crafted for you.</p>
            <button 
              onClick={() => setPage("products")} 
              className="mt-4 bg-[#81D8D0] text-black px-6 py-2 rounded hover:bg-[#5bb8b0]"
            >
              Shop Now
            </button>
          </div>
        </section>
      )}

      {page === "products" && (
        <main className="p-12 grid grid-cols-1 md:grid-cols-3 gap-12 bg-[#f5f5f5]">
          {products.map(p => (
            <ProductCard key={p.id} {...p} addToCart={() => addToCart(p)} />
          ))}
        </main>
      )}

      {page === "cart" && (
        <section className="p-12">
          <h2 className="text-2xl font-bold mb-4">Your Cart</h2>
          {cart.length === 0 ? (
            <p className="text-gray-600">Your cart is empty.</p>
          ) : (
            <>
              <ul>
                {cart.map((item, index) => (
                  <li key={index} className="bg-white shadow rounded p-4 mb-2 flex justify-between items-center">
                    <span>{item.name} - KSh {item.price.toLocaleString()}</span>
                    <button 
                      onClick={() => removeFromCart(index)} 
                      className="bg-red-600 text-white px-3 py-1 rounded hover:bg-red-800"
                    >
                      Remove
                    </button>
                  </li>
                ))}
              </ul>
              <div className="mt-4 font-bold">Total: KSh {totalPrice.toLocaleString()}</div>
              <button 
                onClick={() => setPage("checkout")} 
                className="mt-4 bg-[#81D8D0] text-black px-4 py-2 rounded hover:bg-[#5bb8b0]"
              >
                Proceed to Checkout
              </button>
            </>
          )}
        </section>
      )}

      {page === "checkout" && (
        <section className="p-12">
          <h2 className="text-2xl font-bold mb-4">Checkout</h2>
          <p className="text-gray-600 mb-4">Total Amount: KSh {totalPrice.toLocaleString()}</p>
          <form className="bg-white shadow rounded p-6 max-w-md mx-auto">
            <label className="block mb-2">Name on Card</label>
            <input type="text" className="border p-2 w-full mb-4" placeholder="John Doe" />

            <label className="block mb-2">Card Number</label>
            <input type="text" className="border p-2 w-full mb-4" placeholder="1234 5678 9012 3456" />

            <label className="block mb-2">Expiry Date</label>
            <input type="text" className="border p-2 w-full mb-4" placeholder="MM/YY" />

            <label className="block mb-2">CVV</label>
            <input type="text" className="border p-2 w-full mb-4" placeholder="123" />

            <button type="submit" className="bg-[#81D8D0] text-black px-4 py-2 rounded hover:bg-[#5bb8b0]">
              Pay Now
            </button>
          </form>
        </section>
      )}

      {page === "contact" && (
        <footer className="bg-[#81D8D0] p-4 text-center">
          <p className="text-black">Contact us at info@luxejewels.com</p>
        </footer>
      )}
    </div>
  );
}

export default App;
